import React, {useContext} from "react";
import {type ChartOptions} from "chart.js";
import {Chart} from "primereact/chart";
import ChartContainer from "../WidgetContainer";
import {generateLineData} from "../helpers/data";
import {WidgetsContext} from "../context";
import {type ILineChartProps} from "@lmb-it/kitsconcerto-types";
import {Skeleton} from "primereact/skeleton";

const LineChart = () => {
  const {
    isLoading,
    id = Math.random().toString(16).slice(2),
    data: dataProp,
    colors,
    isDarkMode,
    aspectRatio = undefined,
  } = useContext(WidgetsContext);

  const { data } = dataProp as ILineChartProps;

  const lineOptions = {
    color: colors.labels,
    scales: {
      x: {
        grid: {
          color: "transparent",
        },
        ticks: {
          color: colors.gridLines,
          autoSkip: true,
          maxTicksLimit: 15,
        },
      },
      y: {
        grid: {
          color: colors.gridLines,
        },
        ticks: {
          color: colors.gridLines,
          autoSkip: true,
          maxTicksLimit: 15,
        },
      },
    },
    elements: {
      line: {
        tension: 0.35,
      },
    },
    interaction: {
      mode: "index",
      intersect: false,
    },
    responsive: true,
    maintainAspectRatio: false,
    aspectRatio,
    plugins: {
      legend: {
        labels: {
          usePointStyle: true,
        },
      },
    },
  } as ChartOptions<"line">;

  return (
    <ChartContainer>
      {!isLoading ? (
        <Chart
          type={"line"}
          id={id}
          options={lineOptions}
          width={"100%"}
          height={"100%"}
          data={generateLineData(data, isDarkMode)}
        />
      ) : (
        <Skeleton height="100%" width={"100%"} />
      )}
    </ChartContainer>
  );
};

export default LineChart;
